<?php
 namespace WPAICG\AutoGPT\Cron\Init; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Scheduler; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Event_Processor; if (!defined('ABSPATH')) { exit; } function attach_individual_task_hooks_logic(\wpdb $wpdb, string $tasks_table_name): void { if (!class_exists(AIPKit_Automated_Task_Scheduler::class) || !class_exists(AIPKit_Automated_Task_Event_Processor::class)) { return; } $all_tasks = $wpdb->get_results("SELECT id FROM " . esc_sql($tasks_table_name), ARRAY_A); if ($all_tasks) { foreach ($all_tasks as $task) { $task_id = (int)$task['id']; $task_specific_hook = AIPKit_Automated_Task_Scheduler::get_task_specific_cron_hook($task_id); if (!has_action($task_specific_hook, [AIPKit_Automated_Task_Event_Processor::class, 'trigger_task_event'])) { add_action($task_specific_hook, [AIPKit_Automated_Task_Event_Processor::class, 'trigger_task_event'], 10, 1); } } } } 